/**
 * @version v1.10.13
 * @tagTime 7/30/2025, 1:53:55 PM
 * hortor HSDK 类型定义, 合并了各个平台的接口
 *
 * 接口规范如下
 *
 * type FooBarOption = FooBarOptionWX | FooBarOptionAPP
 * type FooBarResult = FooBarResultWX | FooBarResultAPP
 *
 * function FooBar (opt: FooBarOption): Promise<FooBarResult>
 *
 * HSDK.d.ts定义了命名空间HSDK, 所有api和类型定义在该命名空间下
 * HSDK.d.ts提供的枚举类型命名规范为大驼峰HSDK.FooBar , 且都在window下的HSDK里有实现
 *
 * 开发注意:
 * 1, 区分平台写类型定义
 * 2, 字段按重要程度优先级排列
 * 3, 字段命名和注释不要重复冗余
 * 4, 删除不必要的类型定义
 */
/**
 * @declare 人机校验的命名空间
 */
declare namespace VERIFY {
	/**
	!#zh 人机校验2.0
	@param opt 验证参数

	@example
	```js
	VERIFY.turnpass({
		gameId: 'x',
		node: node as cc.Node,
		uniqueId: 'xxx',
		env: HSDK.ENV.Test,
		listener: function (): void {console.log('listener') }
	})
	```
	*/
	function turnpass(opt: CaptchaOption): Promise<void>

	/** 人机校验参数 */
	type CaptchaOption = {
		/** 挂载的父节点 cc.Node */
		node: any
		/** 每次失败时，会触发回调该函数 */
		listener: (opt: { errMsg?: string; errCode?: number }) => void
	}

	/** 挂载人机校验sdk */
	function bootstrap(opt: VerifyInitOpt): void

	/** 挂载人机校验参数 */
	type VerifyInitOpt = {
		gameId: string
		uniqueId: string
		env: HSDK.ENV
	}
}

