		gameTp: string
		/** 平台id */
		uniqueId: string
		/** 系统信息 */
		sysInfo: {
			/** 操作系统 */
			deviceSystem: string
			/** 设备型号 */
			deviceModel: string
			/** 设备品牌 */
			deviceBrand: string
			/** 设备版本 */
			deviceVersion: string
			/** hsdk版本 */
			hortorSDKVersion: string
			/** 设备名称 */
			deviceName: string
		}
	}

	/** 获取设备信息 */
	function getDeviceInfo(): Promise<GetDeviceInfoResult>

	type GetAppInfoResult = {
		/** 宿主APP名称 */
		appName:
			| 'Toutiao' // 今日头条
			| 'Douyin' // 抖音（国内版)
			| 'news_article_lite' // 今日头条（极速版)
			| 'douyin_lite' // 抖音（极速版）
			| 'aweme_hotsoon' // 抖音火山版
			| 'XiGua' // 西瓜
			| 'novel_fm' // 番茄畅听
			| 'novelapp' // 番茄小说
			| 'devtools' // 开发者工具
	}

	/** 获取宿主APP信息 */
	function getAppInfo(): Promise<GetAppInfoResult>

	/**
	 * 添加桌面图标的参数
	 * */
	type AddShortcutOption = {
		// 海外h5页面需要填写, google商店或apple store的应用id
		id?: string
		// 美团小游戏需要填写, 快捷方式的名称
		label?: string
		// 美团小游戏需要填写, 跳转页面, 找对接人员获取, 如果游戏未发布上线，使用该链接跳转可能会失败，游戏发布线上版本即可跳转。
		target?: string
		// 华为小游戏需要传入, 其他平台不需要传入
		msg?: string
		[props: string]: any
	}

	/** 检查桌面图标的结果 */
	type CheckShortcutResult = {
		/** 是否已创建桌面图标, 全平台返回 */
		hasDesktopIcon: boolean
		/** 是否可以添加快捷方式, 只有抖音小游戏和快手小游戏会返回 */
		canAdd: boolean
		/** 是否需要更新快捷方式, 只有抖音小游戏会返回 */
		needUpdate: boolean
	}

	/** 获取是否从桌面图标快捷方式打开的结果 */
	type GetIsOpenFromShortcutResult = {
		/** 是否从桌面图标快捷方式打开, 全平台返回 */
		isOpenFromShortcut: boolean
	}

	/** 获取是否可以添加到侧边栏的结果 */
	type GetCanAddToSideBarResult = {
		/** 是否可以添加到侧边栏, 全平台返回 */
		canAddToSideBar: boolean
	}

	/** 获取是否从侧边栏打开的结果 */
	type GetIsOpenFromSideBarResult = {
		/** 是否从侧边栏打开, 全平台返回 */
		isOpenFromSideBar: boolean
	}

	/** 获取日志管理器 */
	interface GetLogManagerOption {
		level?: 0 | 1
		syncToConsole?: boolean
	}

	interface GetLogManagerResult {
		log: (message: string, ...args: any[]) => void
		debug: (message: string, ...args: any[]) => void
		info: (message: string, ...args: any[]) => void
		warn: (message: string, ...args: any[]) => void
		error: (message: string, ...args: any[]) => void
	}
}
